    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            Object expires = Helpers.multiply((Helpers.add(this.milliseconds(), this.safeInteger(this.options, "requestExpiration", 5000))), 1000); // need macroseconds
            Object wsOptions = this.safeDict(this.options, "ws", new java.util.HashMap<String, Object>() {{}});
            Object authenticated = this.safeString(wsOptions, "token");
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object method = "GET";
                Object bodyStr = "";
                Object path = "ws";
                Object payload = Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.apiKey, String.valueOf(expires)), ((String)method).toUpperCase()), "/"), path), bodyStr);
                Object decodedSecret = this.base64ToBinary(this.secret);
                Object signature = this.hmac(this.encode(payload), decodedSecret, sha256(), "base64");
                Object defaultOptions = new java.util.HashMap<String, Object>() {{
                    put( "ws", new java.util.HashMap<String, Object>() {{
                        put( "options", new java.util.HashMap<String, Object>() {{
                            put( "headers", new java.util.HashMap<String, Object>() {{
                                put( "Content-Type", "application/json" );
                                put( "Accept", "application/json" );
                                put( "Arkham-Api-Key", ArkhamCore.this.apiKey );
                                put( "Arkham-Expires", String.valueOf(expires) );
                                put( "Arkham-Signature", signature );
                            }} );
                        }} );
                    }} );
                }};
                this.extendExchangeOptions(defaultOptions);
                this.client(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"));
            }
            return null;
        });

    }

